import{_ as t,o as n,c as r,ag as a}from"./chunks/framework.B9unkguw.js";const d=JSON.parse('{"title":"어플리케이션 설정 화면","description":"","frontmatter":{},"headers":[],"relativePath":"ko/qgc-user-guide/settings_view/settings_view.md","filePath":"ko/qgc-user-guide/settings_view/settings_view.md"}'),o={name:"ko/qgc-user-guide/settings_view/settings_view.md"};function s(i,e,g,l,p,h){return n(),r("div",null,e[0]||(e[0]=[a('<h1 id="어플리케이션-설정-화면" tabindex="-1">어플리케이션 설정 화면 <a class="header-anchor" href="#어플리케이션-설정-화면" aria-label="Permalink to &quot;어플리케이션 설정 화면&quot;">​</a></h1><p>_설정 화면_은 일반 기체들의 <em>QGroundControl</em> 애플리케이션을 설정합니다. 이 값을 변경하기 위하여 기체를 연결할 필요는 없습니다.</p><p>You can switch between the various settings pages by clicking the buttons in the left-sidebar.</p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><p>Use the <strong>search bar</strong> at the top of the settings sidebar to find any setting by name. As you type, matching settings are shown across all pages — click a result to jump directly to that setting. This is the fastest way to find a setting when you don&#39;t know which page it&#39;s on.</p><h2 id="settings-pages" tabindex="-1">Settings Pages <a class="header-anchor" href="#settings-pages" aria-label="Permalink to &quot;Settings Pages&quot;">​</a></h2><p><strong><a href="./general.html">General</a></strong> <br>The main application configuration settings: display units, autoconnection devices, language, color scheme, and other core options.</p><p><strong><a href="./fly_view.html">Fly View</a></strong> <br>Configure Fly View behavior: preflight checklist, guided mode, virtual joystick, and instrument panel options.</p><p><strong><a href="./3d_view.html">3D View</a></strong> <br>Enable and configure the 3D map view.</p><p><strong><a href="./plan_view.html">Plan View</a></strong> <br>Configure Plan View defaults: mission altitude, VTOL transition distance, and landing pattern options.</p><p><strong><a href="./adsb_server.html">ADSB Server</a></strong> <br>Configure the ADS-B traffic tracking server connection for nearby aircraft display.</p><p><strong><a href="./comm_links.html">Comm Links</a></strong> <br>Manually create communication links and configure auto-connect options.</p><p><strong><a href="./console_logging.html">Logging</a></strong> <br>Capture application logs for help with diagnosing problems.</p><p><strong><a href="./maps.html">Maps</a></strong> <br>Map provider selection, offline tile management, API tokens, custom tile servers, and cache settings.</p><p><strong><a href="./ntrip_rtk.html">NTRIP / RTK</a></strong> <br>Configure the built-in NTRIP client for streaming RTK correction data to the vehicle.</p><p><strong><a href="./px4_log_transfer.html">PX4 Log Transfer</a></strong> <br>Configure PX4 log download and upload settings.</p><p><strong><a href="./remote_id.html">Remote ID</a></strong> <br>Configure drone Remote ID settings including registration, region, and operator information.</p><p><strong><a href="./telemetry.html">Telemetry</a></strong> <br>Settings associated with the MAVLink connection to a vehicle.</p><p><strong><a href="./video.html">Video</a></strong> <br>Configure video source, stream URL, recording options, and decoder settings.</p><p><strong><a href="./help.html">Help</a></strong> <br>Links to QGroundControl user guide, forums, and support resources.</p>',20)]))}const u=t(o,[["render",s]]);export{d as __pageData,u as default};
